Code2:
#include <bits/stdc++.h>
using namespace std;

int main() {
 int T;
 while(T--){
 int X,Y,N,R;
 cin>>X>>Y>>N>>R;

 vector<pair<int,int>> dp;

 for(int r=0;r<N*X;r++){
 dp[r].first=-1;
 dp[r].second=-1;
 }

 int i=N*X;
 dp[i].first=N;
 dp[i].second=0;

 while(i<=R){
 int diff=Y-X;

 for(int j=i;j<i+diff;j++){
 dp[i+1]=dp[i];
 }

 int left=dp[i].first;
 int right=dp[i].second;
 i=i+diff;
 dp[i].first=left-1;
 dp[i].second=right+1;
 }

 cout<<dp[R].first<<""<<dp[R].second;
 }

 return 0;

}

