Code2:
#include <bits/stdc++.h>
using namespace std;

int main() {
 // your code goes here
 int t;
 cin >> t;

 while(t--) {
  int X,Y;
  long long N, R;
  cin >> X >> Y >> N >> R;
  if(R < X) return -1;

  int premBurger = 0;
  int normBurger = 0;

  long long cost = R;
  long long rem_burger = N;

  vector<long long> dp(premBurger + 1, 0);
  while(rem_burger <= N) {
   if(rem_burger == 0) break;

   while(cost){
    if(Y < cost && (Y + (rem_burger - 1)*X <= cost)) {
     premBurger += 1;
     rem_burger -= 1;
     cost -= Y;
    }
    else {
     normBurger += 1;
     rem_burger -= 1;
     cost -= X;
    }
   }
  }
  cout << normBurger << " " << premBurger << "\n";
 }
 return 0;
}

