#include <bits/stdc++.h>
using namespace std;


void max_burgers(int x,int y,int n,int r){
 int count_n=0;
 int count_p=0;
 if((x*n<=r)||(y*n<=r)){
  for(int i=0;i<n;i++){
   if((i)*y<=r && ((n-i)*x)<=r-(i)*y){
    count_n=n-i;
    count_p=i;
   }
  }
 }


 int count=count_n+count_p;
 if(count == n){
  cout<<count_n<<" "<<count_p<<endl;
 }
 else cout<<-1;

}
int main() {
 // your code goes here
 int t;
 cin>>t;

 while(t>0){
  int x,y,n,r;
  cin>>x;
  cin>>y;
  cin>>n;
  cin>>r;
  max_burgers(x,y,n,r);
 }
}

