#include <bits/stdc++.h>
using namespace std;
int maxPairs(int arr, int n){
 if(n == 0) return 0;
 int pairs = 0;
 int i = 1;
 int j = i+1;

 while(i <= n && j <= n){
  if(arr[i] != arr[j]){
   pairs++;
   i = j+1;
   j = j+1;
  }
  else{
   i = j;
   j = j+1;
  }
 }
 return pairs;
}

