#include <bits/stdc++.h>
using namespace std;
void buyBurgers(int X,int Y,int n,int R){ //2 10 4 12
 if(R == 0){ cout<<-1; return;}
 if(n == 0){ cout<<0<<" "<<0; return;}
 int normal = 0,premium = 0;
 int count = 0;
 while(R > 0 && count < n){
  if(R >= Y){
   count++;
   premium++;
   R = R - Y;
   continue;
  }
  else if(R >= X){
   count++;
   normal++;
   R = R - X;
   continue;
  }
  else{
   break;
  }
 }
 if(count < n){
  cout<<-1;
  return;
 }
  cout<<normal<<" "<<premium;
}

int main() {
 int X,Y,N,R;
 cin>>X>>Y>>N>>R;
 buyBurgers(X,Y,N,R);
 return 0;
}

